     1→import {
     2→  Masthead,
     3→  MastheadBrand,
     4→  MastheadContent,
     5→  MastheadMain,
     6→  MastheadToggle,
     7→  Page,
     8→  PageSection,
     9→  PageSidebar,
    10→  PageSidebarBody,
    11→  Button,
    12→  Toolbar,
    13→  ToolbarContent,
    14→  ToolbarGroup,
    15→  ToolbarItem,
    16→  Label,
    17→  Title,
    18→} from "@patternfly/react-core";
    19→import { BarsIcon, MinusIcon, PlusIcon, ExpandIcon, SunIcon, MoonIcon } from "@patternfly/react-icons";
    20→import { useState, useMemo, useEffect } from "react";
    21→import { CanvasContainer } from "./components/canvas/CanvasContainer";
    22→import { TaskDetailPanel } from "./components/panels/TaskDetailPanel";
    23→import { FleetSidebarContent } from "./components/sidebar/FleetSidebar";
    24→import { getLODLevel, useViewport } from "./stores/viewport";
    25→import { useScenario, SCENARIO_COLORS } from "./stores/scenario";
    26→import { generateMockTasks, tasksToSoA } from "./utils/mockData";
    27→import { detectConflicts, getConflictingTaskIndices } from "./utils/conflictDetection";
    28→import { MOCK_RESOURCE_PROJECTION } from "./utils/resourceUtils";
    29→import { getUtilizationStatus } from "./types/resource";
    30→import type { UtilizationStatus } from "./types/resource";
    31→
    32→type Theme = "light" | "dark";
    33→
    34→// Map utilization status to PatternFly label color
    35→function getUtilizationColor(status: UtilizationStatus): "green" | "yellow" | "orange" | "red" {
    36→  switch (status) {
    37→    case "optimal": return "green";
    38→    case "under_utilized": return "yellow";
    39→    case "near_capacity": return "orange";
    40→    case "overloaded": return "red";
    41→  }
    42→}
    43→
    44→export function App() {
    45→  const [sidebarOpen, setSidebarOpen] = useState(true);
    46→  const [theme, setTheme] = useState<Theme>("light"); // Default to light
    47→  const { state: viewportState, actions: viewportActions } = useViewport();
    48→  const { state: scenarioState, actions: scenarioActions } = useScenario();
    49→
    50→  // Apply theme to document
    51→  useEffect(() => {
    52→    document.documentElement.setAttribute("data-theme", theme);
    53→  }, [theme]);
    54→
    55→  const toggleTheme = () => {
    56→    setTheme((prev) => (prev === "light" ? "dark" : "light"));
    57→  };
    58→
    59→  const lodLevel = getLODLevel(viewportState.zoom);
    60→  const scenarioColors = SCENARIO_COLORS[scenarioState.mode];
    61→
    62→  // Generate mock task data (same as CanvasContainer)
    63→  const tasks = useMemo(() => {
    64→    const rawTasks = generateMockTasks(128, 12, 4); // 128 trains, 12 years, ~4 tasks/year
    65→    return tasksToSoA(rawTasks);
    66→  }, []);
    67→
    68→  // Compute conflicts
    69→  const { conflicts, conflictIndices } = useMemo(() => {
    70→    const detected = detectConflicts(tasks);
    71→    const indices = getConflictingTaskIndices(detected);
    72→    return { conflicts: detected, conflictIndices: indices };
    73→  }, [tasks]);
    74→
    75→  // Compute utilization from resource projection
    76→  const utilization = useMemo(() => {
    77→    const currentYear = new Date().getFullYear();
    78→    const yearlyData = MOCK_RESOURCE_PROJECTION.yearlySummaries.find(
    79→      (y) => y.year === currentYear
    80→    );
    81→
    82→    // Use first year if current year not found, or sensible default
    83→    const avgUtilization = yearlyData?.averageUtilization
    84→      ?? MOCK_RESOURCE_PROJECTION.yearlySummaries[0]?.averageUtilization
    85→      ?? 85;
    86→
    87→    return {
    88→      percent: Math.round(avgUtilization),
    89→      status: getUtilizationStatus(avgUtilization),
    90→    };
    91→  }, []);
    92→
    93→  const header = (
    94→    <Masthead>
    95→      <MastheadMain>
    96→        <MastheadToggle>
    97→          <Button
    98→            variant="plain"
    99→            onClick={() => setSidebarOpen(!sidebarOpen)}
   100→            aria-label="Toggle sidebar"
   101→          >
   102→            <BarsIcon />
   103→          </Button>
   104→        </MastheadToggle>
   105→        <MastheadBrand>
   106→          <Title headingLevel="h1" size="lg" style={{ color: "white" }}>
   107→            MMS
   108→          </Title>
   109→        </MastheadBrand>
   110→      </MastheadMain>
   111→      <MastheadContent>
   112→        <Toolbar>
   113→          <ToolbarContent>
   114→            {/* Zoom Controls */}
   115→            <ToolbarGroup variant="action-group">
   116→              <ToolbarItem>
   117→                <Button variant="plain" onClick={() => viewportActions.zoomOut()} aria-label="Zoom out">
   118→                  <MinusIcon />
   119→                </Button>
   120→              </ToolbarItem>
   121→              <ToolbarItem>
   122→                <Label isCompact>{(viewportState.zoom * 100).toFixed(0)}%</Label>
   123→              </ToolbarItem>
   124→              <ToolbarItem>
   125→                <Button variant="plain" onClick={() => viewportActions.zoomIn()} aria-label="Zoom in">
   126→                  <PlusIcon />
   127→                </Button>
   128→              </ToolbarItem>
   129→              <ToolbarItem>
   130→                <Button variant="plain" onClick={() => viewportActions.resetView()} aria-label="Fit to view">
   131→                  <ExpandIcon />
   132→                </Button>
   133→              </ToolbarItem>
   134→            </ToolbarGroup>
   135→
   136→            {/* LOD Indicator */}
   137→            <ToolbarGroup variant="action-group">
   138→              <ToolbarItem>
   139→                <Label
   140→                  color={lodLevel === "MACRO" ? "orange" : lodLevel === "MESO" ? "blue" : "green"}
   141→                >
   142→                  {lodLevel}
   143→                </Label>
   144→              </ToolbarItem>
   145→            </ToolbarGroup>
   146→
   147→            {/* Mode Toggle */}
   148→            <ToolbarGroup variant="action-group">
   149→              <ToolbarItem>
   150→                <Button
   151→                  variant="plain"
   152→                  onClick={() => scenarioActions.toggleMode()}
   153→                  style={{
   154→                    padding: "4px 12px",
   155→                    borderRadius: "16px",
   156→                    backgroundColor: scenarioState.mode === "sandbox" ? "#7c3aed" : "#0066cc",
   157→                    color: "white",
   158→                    fontWeight: 500,
   159→                  }}
   160→                >
   161→                  {scenarioColors.label}
   162→                  {scenarioState.isDirty && " *"}
   163→                </Button>
   164→              </ToolbarItem>
   165→              {scenarioState.mode === "sandbox" && scenarioState.modifications.size > 0 && (
   166→                <ToolbarItem>
   167→                  <Label isCompact color="purple">
   168→                    {scenarioState.modifications.size} changes
   169→                  </Label>
   170→                </ToolbarItem>
   171→              )}
   172→            </ToolbarGroup>
   173→
   174→            {/* Theme Toggle */}
   175→            <ToolbarGroup variant="action-group">
   176→              <ToolbarItem>
   177→                <button
   178→                  onClick={toggleTheme}
   179→                  className="theme-toggle-btn"
   180→                  aria-label={`Switch to ${theme === "light" ? "dark" : "light"} theme`}
   181→                  title={`Switch to ${theme === "light" ? "dark" : "light"} theme`}
   182→                >
   183→                  {theme === "light" ? <MoonIcon /> : <SunIcon />}
   184→                  <span style={{ color: "var(--mms-text-primary)" }}>
   185→                    {theme === "light" ? "Dark" : "Light"}
   186→                  </span>
   187→                </button>
   188→              </ToolbarItem>
   189→            </ToolbarGroup>
   190→
   191→            {/* KPIs */}
   192→            <ToolbarGroup align={{ default: "alignEnd" }}>
   193→              <ToolbarItem>
   194→                <Label isCompact>Tasks: {tasks.count.toLocaleString()}</Label>
   195→              </ToolbarItem>
   196→              <ToolbarItem>
   197→                <Label isCompact color={conflicts.length > 0 ? "red" : "green"}>
   198→                  Conflicts: {conflicts.length}
   199→                </Label>
   200→              </ToolbarItem>
   201→              <ToolbarItem>
   202→                <Label isCompact color={getUtilizationColor(utilization.status)}>
   203→                  Utilization: {utilization.percent}%
   204→                </Label>
   205→              </ToolbarItem>
   206→            </ToolbarGroup>
   207→          </ToolbarContent>
   208→        </Toolbar>
   209→      </MastheadContent>
   210→    </Masthead>
   211→  );
   212→
   213→  const sidebar = (
   214→    <PageSidebar isSidebarOpen={sidebarOpen}>
   215→      <PageSidebarBody style={{ height: "calc(100vh - 73px)" }}>
   216→        <FleetSidebarContent />
   217→      </PageSidebarBody>
   218→    </PageSidebar>
   219→  );
   220→
   221→  return (
   222→    <Page masthead={header} sidebar={sidebar} className={theme === "dark" ? "pf-v6-theme-dark" : "pf-v6-theme-light"} style={{ height: "100vh" }}>
   223→      <PageSection
   224→        isFilled
   225→        padding={{ default: "noPadding" }}
   226→        style={{
   227→          backgroundColor: "var(--mms-bg-canvas)",
   228→          position: "relative",
   229→          height: "calc(100vh - 73px)", // Subtract header height
   230→          minHeight: "calc(100vh - 73px)",
   231→        }}
   232→      >
   233→        <TaskDetailPanel tasks={tasks} conflictIndices={conflictIndices}>
   234→          <CanvasContainer tasks={tasks} />
   235→        </TaskDetailPanel>
   236→      </PageSection>
   237→    </Page>
   238→  );
   239→}
