import { useSyncExternalStore } from "react";

// Viewport state for camera position and zoom
export interface ViewportState {
  // Camera position (world coordinates)
  x: number;
  y: number;
  // Zoom level (1.0 = 100%)
  zoom: number;
  // Viewport dimensions (pixels)
  width: number;
  height: number;
  // Interaction state
  isDragging: boolean;
  // Inertia velocity
  velocityX: number;
  velocityY: number;
}

// LOD level based on zoom
export type LODLevel = "MACRO" | "MESO" | "MICRO";

// LOD thresholds with 15% hysteresis
const LOD_THRESHOLDS = {
  MACRO_TO_MESO: 0.5,
  MESO_TO_MICRO: 2.0,
  // Hysteresis zones
  MACRO_MESO_LOW: 0.425,
  MACRO_MESO_HIGH: 0.575,
  MESO_MICRO_LOW: 1.7,
  MESO_MICRO_HIGH: 2.3,
} as const;

// Zoom constraints
const ZOOM_MIN = 0.05;
const ZOOM_MAX = 5.0;
const ZOOM_FACTOR = 1.5;

// World bounds (128 trains × 12 years × 365 days)
// DAY_WIDTH=2px, so 12 years = 12*365*2 = 8,760px
const WORLD_BOUNDS = {
  minX: 0,
  maxX: 12 * 365 * 2, // 12 years × 365 days × 2px = 8,760px
  minY: -128 * 24, // 128 trains (24px per train, negative Y down)
  maxY: 0,
};

// Initial state - center view on year 1 with all trains visible
// DAY_WIDTH=2px, TRAIN_HEIGHT=24px
// Year 1 center: day 182 × 2px = 364px
// All trains center: 64 trains × 24px = 1,536px
const initialState: ViewportState = {
  x: 730, // Center on middle of year 1 (365 days × 2px)
  y: -1536, // Center on train 64 (middle of 128 trains × 24px)
  zoom: 0.3, // Zoomed out to see ~3 years and all trains
  width: 1280,
  height: 720,
  isDragging: false,
  velocityX: 0,
  velocityY: 0,
};

// Store implementation using vanilla JS with useSyncExternalStore pattern
type Listener = () => void;

class ViewportStore {
  private state: ViewportState;
  private listeners: Set<Listener> = new Set();

  constructor() {
    this.state = { ...initialState };
  }

  getState = (): ViewportState => this.state;

  subscribe = (listener: Listener): (() => void) => {
    this.listeners.add(listener);
    return () => this.listeners.delete(listener);
  };

  private notify = () => {
    this.listeners.forEach((listener) => listener());
  };

  private clampToBounds = () => {
    this.state.x = Math.max(WORLD_BOUNDS.minX, Math.min(WORLD_BOUNDS.maxX, this.state.x));
    this.state.y = Math.max(WORLD_BOUNDS.minY, Math.min(WORLD_BOUNDS.maxY, this.state.y));
  };

  // Actions
  pan = (dx: number, dy: number) => {
    this.state = {
      ...this.state,
      x: this.state.x - dx / this.state.zoom,
      y: this.state.y - dy / this.state.zoom,
    };
    this.clampToBounds();
    this.notify();
  };

  zoomToPoint = (factor: number, screenX: number, screenY: number) => {
    const newZoom = Math.max(ZOOM_MIN, Math.min(ZOOM_MAX, this.state.zoom * factor));

    // Zoom toward cursor position
    const worldX = this.state.x + (screenX - this.state.width / 2) / this.state.zoom;
    const worldY = this.state.y + (screenY - this.state.height / 2) / this.state.zoom;

    this.state = {
      ...this.state,
      zoom: newZoom,
      x: worldX - (screenX - this.state.width / 2) / newZoom,
      y: worldY - (screenY - this.state.height / 2) / newZoom,
    };
    this.clampToBounds();
    this.notify();
  };

  zoomIn = () => {
    this.state = {
      ...this.state,
      zoom: Math.min(ZOOM_MAX, this.state.zoom * ZOOM_FACTOR),
    };
    this.notify();
  };

  zoomOut = () => {
    this.state = {
      ...this.state,
      zoom: Math.max(ZOOM_MIN, this.state.zoom / ZOOM_FACTOR),
    };
    this.notify();
  };

  resetView = () => {
    this.state = {
      ...initialState,
      width: this.state.width,
      height: this.state.height,
    };
    this.notify();
  };

  panTo = (worldX: number, worldY: number) => {
    this.state = {
      ...this.state,
      x: worldX,
      y: worldY,
    };
    this.clampToBounds();
    this.notify();
  };

  setSize = (width: number, height: number) => {
    this.state = { ...this.state, width, height };
    this.notify();
  };

  startDrag = () => {
    this.state = {
      ...this.state,
      isDragging: true,
      velocityX: 0,
      velocityY: 0,
    };
    this.notify();
  };

  endDrag = (vx: number, vy: number) => {
    this.state = {
      ...this.state,
      isDragging: false,
      velocityX: vx,
      velocityY: vy,
    };
    this.notify();
  };

  applyInertia = () => {
    if (this.state.isDragging) return;
    if (Math.abs(this.state.velocityX) < 0.1 && Math.abs(this.state.velocityY) < 0.1) {
      if (this.state.velocityX !== 0 || this.state.velocityY !== 0) {
        this.state = { ...this.state, velocityX: 0, velocityY: 0 };
        this.notify();
      }
      return;
    }

    const friction = 0.95;
    this.state = {
      ...this.state,
      x: this.state.x - this.state.velocityX / this.state.zoom,
      y: this.state.y - this.state.velocityY / this.state.zoom,
      velocityX: this.state.velocityX * friction,
      velocityY: this.state.velocityY * friction,
    };
    this.clampToBounds();
    this.notify();
  };

  setZoom = (zoom: number) => {
    this.state = {
      ...this.state,
      zoom: Math.max(ZOOM_MIN, Math.min(ZOOM_MAX, zoom)),
    };
    this.notify();
  };
}

// Create singleton store
export const viewportStore = new ViewportStore();

// React hook for using the store
export function useViewport() {
  const state = useSyncExternalStore(viewportStore.subscribe, viewportStore.getState);
  return {
    state,
    actions: {
      pan: viewportStore.pan,
      panTo: viewportStore.panTo,
      zoomToPoint: viewportStore.zoomToPoint,
      zoomIn: viewportStore.zoomIn,
      zoomOut: viewportStore.zoomOut,
      resetView: viewportStore.resetView,
      setSize: viewportStore.setSize,
      startDrag: viewportStore.startDrag,
      endDrag: viewportStore.endDrag,
      applyInertia: viewportStore.applyInertia,
      setZoom: viewportStore.setZoom,
    },
  };
}

// Selectors
export function getLODLevel(zoom: number): LODLevel {
  if (zoom < LOD_THRESHOLDS.MACRO_TO_MESO) return "MACRO";
  if (zoom >= LOD_THRESHOLDS.MESO_TO_MICRO) return "MICRO";
  return "MESO";
}

export function getLODOpacity(zoom: number): { macro: number; meso: number; micro: number } {
  // Smoothstep function for smooth transitions
  const smoothstep = (edge0: number, edge1: number, x: number) => {
    const t = Math.max(0, Math.min(1, (x - edge0) / (edge1 - edge0)));
    return t * t * (3 - 2 * t);
  };

  let macro = 0;
  let meso = 0;
  let micro = 0;

  if (zoom < LOD_THRESHOLDS.MACRO_MESO_LOW) {
    macro = 1;
  } else if (zoom < LOD_THRESHOLDS.MACRO_MESO_HIGH) {
    macro = 1 - smoothstep(LOD_THRESHOLDS.MACRO_MESO_LOW, LOD_THRESHOLDS.MACRO_MESO_HIGH, zoom);
    meso = smoothstep(LOD_THRESHOLDS.MACRO_MESO_LOW, LOD_THRESHOLDS.MACRO_MESO_HIGH, zoom);
  } else if (zoom < LOD_THRESHOLDS.MESO_MICRO_LOW) {
    meso = 1;
  } else if (zoom < LOD_THRESHOLDS.MESO_MICRO_HIGH) {
    meso = 1 - smoothstep(LOD_THRESHOLDS.MESO_MICRO_LOW, LOD_THRESHOLDS.MESO_MICRO_HIGH, zoom);
    micro = smoothstep(LOD_THRESHOLDS.MESO_MICRO_LOW, LOD_THRESHOLDS.MESO_MICRO_HIGH, zoom);
  } else {
    micro = 1;
  }

  return { macro, meso, micro };
}

// World <-> Screen coordinate conversion
export function worldToScreen(
  worldX: number,
  worldY: number,
  viewport: ViewportState
): { x: number; y: number } {
  const x = (worldX - viewport.x) * viewport.zoom + viewport.width / 2;
  const y = (worldY - viewport.y) * viewport.zoom + viewport.height / 2;
  return { x, y };
}

export function screenToWorld(
  screenX: number,
  screenY: number,
  viewport: ViewportState
): { x: number; y: number } {
  const x = (screenX - viewport.width / 2) / viewport.zoom + viewport.x;
  const y = (screenY - viewport.height / 2) / viewport.zoom + viewport.y;
  return { x, y };
}

// Export types and constants
export { WORLD_BOUNDS, ZOOM_MIN, ZOOM_MAX, LOD_THRESHOLDS };

