// Task types for MMS

export type TaskType = "preventive" | "corrective" | "inspection" | "overhaul";

export interface Task {
  id: string;
  trainId: number;
  type: TaskType;
  startDay: number; // Days from epoch (project start)
  duration: number; // Days
  name: string;
  status: "scheduled" | "in_progress" | "completed" | "conflict";
}

// Task type colors (matching design system)
export const TASK_COLORS: Record<TaskType, string> = {
  preventive: "#0066cc",
  corrective: "#f0ab00",
  inspection: "#6753ac",
  overhaul: "#009596",
};

// Task type colors as RGB for Three.js
export const TASK_COLORS_RGB: Record<TaskType, [number, number, number]> = {
  preventive: [0, 0.4, 0.8], // Blue
  corrective: [0.94, 0.67, 0], // Gold
  inspection: [0.4, 0.33, 0.67], // Purple
  overhaul: [0, 0.58, 0.59], // Teal
};

// Task type display names for labels
export const TASK_TYPE_NAMES: string[] = [
  "Preventive",
  "Corrective",
  "Inspection",
  "Overhaul",
];

/**
 * Centralized render constants for MMS
 *
 * These constants define the coordinate system and sizing used throughout
 * the rendering layers (MACRO, MESO, MICRO) and UI components.
 *
 * Coordinate System:
 * - X axis = Time (days since BASE_DATE)
 * - Y axis = Train (negative, 0 at top)
 * - Each day = DAY_WIDTH pixels at zoom=1
 * - Each train row = TRAIN_HEIGHT pixels at zoom=1
 */

// =============================================================================
// TIME CONSTANTS
// =============================================================================

/** Base date for the planning horizon (Jan 1, 2024) */
export const BASE_DATE = new Date(2024, 0, 1);

/** Total planning horizon in years */
export const PLANNING_YEARS = 12;

/** Days per year (approximate) */
export const DAYS_PER_YEAR = 365;

/** Total days in planning horizon */
export const TOTAL_DAYS = PLANNING_YEARS * DAYS_PER_YEAR;

/** Days per month cell (for MACRO heatmap) */
export const DAYS_PER_CELL = 30;

/** Days per week (for MICRO grid) */
export const DAYS_PER_WEEK = 7;

// =============================================================================
// SPATIAL CONSTANTS (pixels at zoom=1)
// =============================================================================

/** Width of one day in pixels (2px = 1 year fits in ~730px) */
export const DAY_WIDTH = 2;

/** Height of one train row in pixels */
export const TRAIN_HEIGHT = 24;

/** Height of a task block in pixels */
export const TASK_HEIGHT = 20;

/** Width of a month cell (MACRO layer) */
export const CELL_WIDTH = DAYS_PER_CELL * DAY_WIDTH; // 300px

/** Height of a month cell (MACRO layer) */
export const CELL_HEIGHT = TRAIN_HEIGHT;

// =============================================================================
// FLEET CONSTANTS
// =============================================================================

/** Total number of trains in the fleet */
export const TRAIN_COUNT = 128;

/** Number of Kinki Sharyo trains */
export const KINKI_SHARYO_COUNT = 49;

/** Number of Alstom trains */
export const ALSTOM_COUNT = 79;

// =============================================================================
// PERFORMANCE CONSTANTS
// =============================================================================

/** Minimum task width to show labels (MICRO layer) */
export const MIN_LABEL_WIDTH = 40;

/** Maximum number of labels to render at once (MICRO layer) */
export const MAX_LABELS = 50;

// =============================================================================
// WORLD BOUNDS (derived from other constants)
// =============================================================================

/** Maximum X coordinate (end of planning horizon) */
export const WORLD_MAX_X = TOTAL_DAYS * DAY_WIDTH; // 43,800px

/** Minimum Y coordinate (bottom of all train rows) */
export const WORLD_MIN_Y = -TRAIN_COUNT * TRAIN_HEIGHT; // -3,072px

// =============================================================================
// UTILITY FUNCTIONS
// =============================================================================

/**
 * Convert a day number to a Date object
 */
export function dayToDate(dayNumber: number): Date {
  return new Date(BASE_DATE.getTime() + dayNumber * 24 * 60 * 60 * 1000);
}

/**
 * Convert a Date object to a day number
 */
export function dateToDay(date: Date): number {
  return Math.floor((date.getTime() - BASE_DATE.getTime()) / (24 * 60 * 60 * 1000));
}

/**
 * Format a day number as a human-readable date string
 */
export function formatDayAsDate(dayNumber: number): string {
  const date = dayToDate(dayNumber);
  return date.toLocaleDateString("en-US", {
    year: "numeric",
    month: "short",
    day: "numeric",
  });
}

